        import sailpoint.tools.Util;
        import sailpoint.object.Custom;
        import sailpoint.object.Identity;
        import java.text.ParseException;
        import java.text.SimpleDateFormat;
				import java.util.Date;
        String extValue = "";
        String dateString = "";
        Date date = new Date();
        String format = "MM/dd/yyyy";
        String iiqFormat = "yyyy-MM-dd";
        
        
        if(null != identity){
        	extValue = identity.getAttribute("hireDate");
        }  
        
        Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
        try{
          if(custom!=null && Util.isNotNullOrEmpty(custom.get("DateFormat"))){
            iiqFormat = custom.get("DateFormat");
          }
        	if(custom!=null && Util.isNotNullOrEmpty(custom.get("AMITADateFormat"))){
            format = custom.get("AMITADateFormat");
          }
         SimpleDateFormat dateFormatIIQ = new SimpleDateFormat(iiqFormat);
          if(Util.isNotNullOrEmpty(extValue)){
            date = dateFormatIIQ.parse(extValue);
          } 
          SimpleDateFormat dateFormatIIQ = new SimpleDateFormat(format);
          if(null != date){
            dateString = dateFormatIIQ.format(date);
          }  
        }catch(Exception ex){
          // do nothing       
        }
        return dateString;

